/* Mystic Purple Theme */
:root {
  --color-mystic-50: #f5f0ff;
  --color-mystic-100: #ede5ff;
  --color-mystic-200: #dccfff;
  --color-mystic-300: #c4adff;
  --color-mystic-400: #a880ff;
