  --color-mystic-800: #5b21b6;
  --color-mystic-900: #4c1d95;
  --color-mystic-950: #2e1065;
}

@theme {
  --color-mystic-50: #f5f0ff;
  --color-mystic-100: #ede5ff;
  --color-mystic-200: #dccfff;
  --color-mystic-300: #c4adff;
  --color-mystic-400: #a880ff;
  --color-mystic-500: #8b5cf6;
  --color-mystic-600: #7c3aed;
  --color-mystic-700: #6d28d9;
  --color-mystic-800: #5b21b6;
  --color-mystic-900: #4c1d95;
  --color-mystic-950: #2e1065;
}

body {
  margin: 0;
  background: linear-gradient(135deg, #0f0a1a 0%, #1a0f2e 25%, #2e1065 50%, #1a0f2e 75%, #0f0a1a 100%);
  color: #e2d9f0;
  font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
  min-height: 100vh;
}

/* Glass morphism cards */
.glass-card {
  background: rgba(30, 15, 60, 0.6);
  backdrop-filter: blur(12px);
  border: 1px solid rgba(139, 92, 246, 0.2);
  border-radius: 16px;
  transition: all 0.3s ease;
}

.glass-card:hover {
  border-color: rgba(139, 92, 246, 0.5);
  box-shadow: 0 0 20px rgba(139, 92, 246, 0.15);
  transform: translateY(-2px);
}

/* Gradient text */
.gradient-text {
  background: linear-gradient(135deg, #c4adff, #8b5cf6, #a880ff);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* Glow effects */
.glow-purple {
  box-shadow: 0 0 30px rgba(139, 92, 246, 0.3), 0 0 60px rgba(139, 92, 246, 0.1);
}

/* Scrollbar */
::-webkit-scrollbar { width: 8px; }
::-webkit-scrollbar-track { background: #0f0a1a; }
::-webkit-scrollbar-thumb { background: #4c1d95; border-radius: 4px; }
::-webkit-scrollbar-thumb:hover { background: #6d28d9; }

/* Smooth scroll */
html { scroll-behavior: smooth; }

/* Dash preview mockup */
.dash-frame {
  background: linear-gradient(145deg, #1a1035, #23104a);
  border: 1px solid rgba(139, 92, 246, 0.3);
  border-radius: 12px;
  overflow: hidden;
}

@keyframes float {
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-10px); }
}
.float-anim { animation: float 4s ease-in-out infinite; }
